import React from 'react';
import { Card, Stack, Heading, Text, Divider } from '@ggui-ai/design/primitives';

export interface Props {
  /** City name */
  city?: string;
  /** Current temperature */
  temperature?: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition?: string;
  /** Humidity percentage */
  humidity?: number;
  /** Wind speed */
  windSpeed?: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast?: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function WeatherCard(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast = [],
  } = props;

  return (
    <Card shadow="md" padding={24} radius="xl">
      <div aria-label={`Weather in ${city ?? 'Unknown location'}`}>
        <Stack gap={24}>
          {/* Header (Current State) */}
          <Stack direction="horizontal" justify="between" align="center">
            <Stack gap={4}>
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                {city ?? 'Unknown'}
              </Heading>
              <Text size="base" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {condition ?? 'N/A'}
              </Text>
            </Stack>
            <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
              {temperature ?? '--'}°{unit}
            </Text>
          </Stack>

          {/* Current Metrics */}
          <Stack direction="horizontal" gap={24}>
            <Stack gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Humidity
              </Text>
              <Text weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                {humidity ?? '--'}%
              </Text>
            </Stack>
            <Stack gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Wind
              </Text>
              <Text weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed ?? '--'} km/h
              </Text>
            </Stack>
          </Stack>

          {/* Separator */}
          <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          {/* 5-Day Forecast Strip */}
          <Stack direction="horizontal" justify="between" align="stretch">
            {forecast.map((dayData, index) => (
              <Stack key={dayData.day ?? index} align="center" gap={8}>
                <Text variant="bodySmall" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                  {dayData.day ?? '-'}
                </Text>

                <Text as="span" size="2xl" aria-hidden="true">
                  {dayData.icon ?? '☁️'}
                </Text>

                <Stack 
                  direction="horizontal" 
                  gap={8} 
                  aria-label={`High ${dayData.high ?? '--'} degrees, Low ${dayData.low ?? '--'} degrees`}
                >
                  <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    {dayData.high ?? '--'}°
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {dayData.low ?? '--'}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </div>
    </Card>
  );
}

import React from 'react';
import {
  Container,
  Card,
  Stack,
  Heading,
  Text,
  Box,
  Divider
} from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city = "Tokyo",
    temperature = 28,
    condition = "Sunny",
    humidity = 45,
    windSpeed = 8,
    unit = "C",
    forecast = [
      { day: "Mon", icon: "☀️", high: 30, low: 22 },
      { day: "Tue", icon: "⛅", high: 27, low: 20 },
      { day: "Wed", icon: "🌧️", high: 24, low: 18 },
      { day: "Thu", icon: "☁️", high: 25, low: 19 },
      { day: "Fri", icon: "☀️", high: 28, low: 21 }
    ]
  } = props;

  return (
    <Container maxWidth="xs">
      <Card shadow="md" radius="xl" padding="var(--ggui-spacing-6, 24px)">
        <div role="region" aria-label={`Weather forecast for ${city ?? 'unknown'}`}>
          <Stack direction="vertical" align="stretch" gap="var(--ggui-spacing-6, 24px)">

            {/* Top Section */}
            <Stack direction="vertical" align="center" gap="var(--ggui-spacing-2, 8px)">
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                {city ?? '--'}
              </Heading>

              <Stack direction="horizontal" align="start" gap="var(--ggui-spacing-1, 4px)">
                <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                  {temperature ?? '--'}
                </Text>
                <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  °{unit ?? 'C'}
                </Text>
              </Stack>

              <Text variant="bodyLarge" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                {condition ?? '--'}
              </Text>
            </Stack>

            {/* Middle Section (Details) */}
            <Stack direction="horizontal" justify="center" gap="var(--ggui-spacing-4, 16px)">
              <Box 
                paddingX="var(--ggui-spacing-4, 16px)" 
                paddingY="var(--ggui-spacing-2, 8px)" 
                background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
                borderRadius="var(--ggui-shape-radius-full, 9999px)"
              >
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Humidity: {humidity ?? '--'}%
                </Text>
              </Box>
              <Box 
                paddingX="var(--ggui-spacing-4, 16px)" 
                paddingY="var(--ggui-spacing-2, 8px)" 
                background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
                borderRadius="var(--ggui-shape-radius-full, 9999px)"
              >
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Wind: {windSpeed ?? '--'} km/h
                </Text>
              </Box>
            </Stack>

            {/* Divider */}
            <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin="var(--ggui-spacing-1, 4px)" />

            {/* Bottom Section (Forecast) */}
            <Stack direction="horizontal" justify="between" align="stretch">
              {(forecast ?? []).map((day, index) => (
                <Stack key={day?.day ?? index} direction="vertical" align="center" gap="var(--ggui-spacing-2, 8px)">
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {day?.day ?? '-'}
                  </Text>
                  <Text size="2xl">
                    {day?.icon ?? '❓'}
                  </Text>
                  <Stack direction="horizontal" gap="var(--ggui-spacing-1, 4px)" align="center">
                    <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                      {day?.high ?? '-'}°
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {day?.low ?? '-'}°
                    </Text>
                  </Stack>
                </Stack>
              ))}
            </Stack>

          </Stack>
        </div>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Stack, Card, Input, Text, Heading, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

export default function PeriodicTable({ elements }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const uniqueCategories = useMemo(() => {
    const categories = new Set<string>();
    elements?.forEach(el => {
      if (el.category) {
        categories.add(el.category);
      }
    });
    return Array.from(categories);
  }, [elements]);

  const getCategoryColor = (category?: string) => {
    if (!category) return 'var(--ggui-color-surfaceVariant, #f4f4f5)';
    const index = uniqueCategories.indexOf(category);
    const colors = [
      'var(--ggui-color-primary-100, #e0f2fe)',
      'var(--ggui-color-success-100, #dcfce7)',
      'var(--ggui-color-warning-100, #fef3c7)',
      'var(--ggui-color-error-100, #fee2e2)',
      'var(--ggui-color-info-100, #cffafe)',
      'var(--ggui-color-primary-200, #bae6fd)',
      'var(--ggui-color-success-200, #bbf7d0)',
      'var(--ggui-color-warning-200, #fde68a)',
      'var(--ggui-color-error-200, #fecaca)',
      'var(--ggui-color-info-200, #a5f3fc)'
    ];
    return colors[index % colors.length] ?? 'var(--ggui-color-surfaceVariant, #f4f4f5)';
  };

  const selectedElement = useMemo(() => 
    elements?.find(el => el.atomicNumber === selectedAtomicNumber),
  [elements, selectedAtomicNumber]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">

        <Input label="Search Elements" placeholder="Filter by name or symbol..." value={searchQuery} onChange={setSearchQuery} />

        <Box>
          <div style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(18, minmax(0, 1fr))', 
            gap: 'var(--ggui-spacing-1, 4px)' 
          }}>
            {elements?.map((el) => {
              const matchesSearch = !searchQuery || 
                (el.name ?? '').toLowerCase().includes(searchQuery.toLowerCase()) || 
                (el.symbol ?? '').toLowerCase().includes(searchQuery.toLowerCase());

              const isSelected = selectedAtomicNumber === el.atomicNumber;

              return (
                <button
                  key={`element-${el.atomicNumber ?? Math.random()}`}
                  onClick={() => setSelectedAtomicNumber(el.atomicNumber ?? null)}
                  aria-label={`${el.name ?? 'Unknown element'}, Atomic Number ${el.atomicNumber ?? 'Unknown'}`}
                  aria-pressed={isSelected}
                  style={{
                    gridRow: el.row,
                    gridColumn: el.col,
                    opacity: matchesSearch ? 1 : 0.2,
                    pointerEvents: matchesSearch ? 'auto' : 'none',
                    backgroundColor: getCategoryColor(el.category),
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    padding: 'var(--ggui-spacing-1, 4px)',
                    border: `1px solid ${isSelected ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outlineVariant, #e4e4e7)'}`,
                    transition: 'all 200ms ease',
                    cursor: 'pointer',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    position: 'relative',
                    aspectRatio: '1',
                    boxShadow: isSelected ? '0 0 0 2px var(--ggui-color-primary-200, #bae6fd)' : 'none',
                    width: '100%',
                  }}
                  onMouseEnter={(e) => {
                    if (!isSelected) {
                      e.currentTarget.style.borderColor = 'var(--ggui-color-outline, #d4d4d8)';
                      e.currentTarget.style.transform = 'scale(1.05)';
                    }
                  }}
                  onMouseLeave={(e) => {
                    if (!isSelected) {
                      e.currentTarget.style.borderColor = 'var(--ggui-color-outlineVariant, #e4e4e7)';
                      e.currentTarget.style.transform = 'scale(1)';
                    }
                  }}
                  onFocus={(e) => {
                    e.currentTarget.style.outline = '2px solid var(--ggui-color-primary-600, #0284c7)';
                    e.currentTarget.style.outlineOffset = '2px';
                  }}
                  onBlur={(e) => {
                    e.currentTarget.style.outline = 'none';
                  }}
                >
                  <span style={{ 
                    position: 'absolute', 
                    top: '4px', 
                    left: '4px', 
                    fontSize: 'var(--ggui-font-size-xs, 12px)', 
                    color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                    lineHeight: 1
                  }}>
                    {el.atomicNumber}
                  </span>
                  <Text variant="bodyLarge" weight="bold" align="center" color="var(--ggui-color-onSurface, #18181b)">
                    {el.symbol ?? '?'}
                  </Text>
                </button>
              );
            })}
          </div>
        </Box>

        <Stack direction="horizontal" wrap gap="var(--ggui-spacing-4, 16px)" align="center">
          {uniqueCategories.map(category => (
            <Stack key={`legend-${category}`} direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
              <div style={{ 
                width: 'var(--ggui-spacing-4, 16px)', 
                height: 'var(--ggui-spacing-4, 16px)', 
                borderRadius: 'var(--ggui-shape-radius-sm, 4px)', 
                backgroundColor: getCategoryColor(category),
                border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)'
              }} />
              <Text variant="caption">{category}</Text>
            </Stack>
          ))}
        </Stack>

        {selectedElement && (
          <Box margin="var(--ggui-spacing-4, 16px) 0 0 0">
            <Card shadow="md" padding="var(--ggui-spacing-6, 24px)" radius="lg" border>
              <Stack direction="horizontal" gap="var(--ggui-spacing-6, 24px)" align="center" wrap>
                <Box 
                  padding="var(--ggui-spacing-6, 24px)" 
                  background={getCategoryColor(selectedElement.category)} 
                  borderRadius="var(--ggui-shape-radius-md, 8px)"
                >
                  <div style={{ 
                    minWidth: '80px', 
                    minHeight: '80px', 
                    display: 'flex', 
                    flexDirection: 'column', 
                    alignItems: 'center', 
                    justifyContent: 'center' 
                  }}>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {selectedElement.atomicNumber}
                    </Text>
                    <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
                      {selectedElement.symbol ?? '?'}
                    </Heading>
                  </div>
                </Box>

                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                    {selectedElement.name ?? 'Unknown Element'}
                  </Heading>
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    <strong style={{ color: 'var(--ggui-color-onSurface, #18181b)' }}>Category:</strong> {selectedElement.category ?? 'Unknown'}
                  </Text>
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    <strong style={{ color: 'var(--ggui-color-onSurface, #18181b)' }}>Atomic Weight:</strong> {selectedElement.atomicWeight ?? 'Unknown'}
                  </Text>
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    <strong style={{ color: 'var(--ggui-color-onSurface, #18181b)' }}>Grid Position:</strong> Row {selectedElement.row ?? '?'}, Col {selectedElement.col ?? '?'}
                  </Text>
                </Stack>
              </Stack>
            </Card>
          </Box>
        )}

      </Stack>
    </Container>
  );
}
